// Helper: Write content to a file in the fixture repo
static bool write_test_file(const wchar_t* repo_path, const char* rel_path, const char* content) {
    wchar_t full_path[512];
    wchar_t rel_wide[256];
    MultiByteToWideChar(CP_UTF8, 0, rel_path, -1, rel_wide, 256);

    wcscpy_s(full_path, repo_path);
    wcscat_s(full_path, L"\\");
    wcscat_s(full_path, rel_wide);

    // Convert forward slashes to backslashes
    for (wchar_t* p = full_path; *p; p++) {
        if (*p == L'/') *p = L'\\';
    }

    HANDLE hFile = CreateFileW(full_path, GENERIC_WRITE, 0, nullptr,
                               CREATE_ALWAYS, FILE_ATTRIBUTE_NORMAL, nullptr);
    if (hFile == INVALID_HANDLE_VALUE) return false;

    DWORD written;
    BOOL ok = WriteFile(hFile, content, (DWORD)strlen(content), &written, nullptr);
    CloseHandle(hFile);
    return ok && written == strlen(content);
}

// Helper: Read content from a file
static char* read_test_file(const wchar_t* repo_path, const char* rel_path, size_t* out_size) {
    wchar_t full_path[512];
    wchar_t rel_wide[256];
    MultiByteToWideChar(CP_UTF8, 0, rel_path, -1, rel_wide, 256);

    wcscpy_s(full_path, repo_path);
    wcscat_s(full_path, L"\\");
    wcscat_s(full_path, rel_wide);

    // Convert forward slashes to backslashes
    for (wchar_t* p = full_path; *p; p++) {
        if (*p == L'/') *p = L'\\';
    }

    HANDLE hFile = CreateFileW(full_path, GENERIC_READ, FILE_SHARE_READ, nullptr,
                               OPEN_EXISTING, FILE_ATTRIBUTE_NORMAL, nullptr);
    if (hFile == INVALID_HANDLE_VALUE) {
        *out_size = 0;
        return nullptr;
    }

    DWORD size = GetFileSize(hFile, nullptr);
    char* buffer = new char[size + 1];
    DWORD read;
    ReadFile(hFile, buffer, size, &read, nullptr);
    CloseHandle(hFile);

    buffer[read] = '\0';
    *out_size = read;
    return buffer;
}

// Helper: Delete a file
static bool delete_test_file(const wchar_t* repo_path, const char* rel_path) {
    wchar_t full_path[512];
    wchar_t rel_wide[256];
    MultiByteToWideChar(CP_UTF8, 0, rel_path, -1, rel_wide, 256);

    wcscpy_s(full_path, repo_path);
    wcscat_s(full_path, L"\\");
    wcscat_s(full_path, rel_wide);

    for (wchar_t* p = full_path; *p; p++) {
        if (*p == L'/') *p = L'\\';
    }

    return DeleteFileW(full_path) != 0;
}

// Helper: Write binary content to a file (with explicit size, for index files)
static bool write_test_file_binary(const wchar_t* repo_path, const char* rel_path,
                                   const char* content, size_t content_size) {
    wchar_t full_path[512];
    wchar_t rel_wide[256];
    MultiByteToWideChar(CP_UTF8, 0, rel_path, -1, rel_wide, 256);

    wcscpy_s(full_path, repo_path);
    wcscat_s(full_path, L"\\");
    wcscat_s(full_path, rel_wide);

    for (wchar_t* p = full_path; *p; p++) {
        if (*p == L'/') *p = L'\\';
    }

    HANDLE hFile = CreateFileW(full_path, GENERIC_WRITE, 0, nullptr,
                               CREATE_ALWAYS, FILE_ATTRIBUTE_NORMAL, nullptr);
    if (hFile == INVALID_HANDLE_VALUE) return false;

    DWORD written;
    BOOL ok = WriteFile(hFile, content, (DWORD)content_size, &written, nullptr);
    CloseHandle(hFile);
    return ok && written == content_size;
}

