TEST(status_detect_modified_worktree) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // Backup original file content
    size_t orig_size = 0;
    char* orig_content = read_test_file(TEST_REPO_PATH, "file1.txt", &orig_size);
    if (!orig_content) {
        git_repo_close(&repo);
        TEST_SKIP("Could not read file1.txt");
    }

    // Modify the file
    bool wrote = write_test_file(TEST_REPO_PATH, "file1.txt", "modified content\n");
    TEST_ASSERT_TRUE(wrote);

    // Compute status
    GitStatus status = {};
    bool result = git_status_compute(&repo, &status);
    TEST_ASSERT_TRUE(result);

    // Should detect modified file in unstaged
    bool found_modified = false;
    for (size_t i = 0; i < status.unstaged_count; i++) {
        if (strcmp(status.unstaged[i].path, "file1.txt") == 0) {
            found_modified = (status.unstaged[i].worktree_status == GitFileStatus::Modified);
            break;
        }
    }

    // Restore original content
    write_test_file(TEST_REPO_PATH, "file1.txt", orig_content);
    delete[] orig_content;

    git_status_free(&status);
    git_repo_close(&repo);

    TEST_ASSERT_TRUE(found_modified);
}

