TEST(status_detect_staged_modification) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // Backup original index
    size_t index_size = 0;
    char* index_backup = read_test_file(TEST_REPO_PATH, ".git/index", &index_size);
    if (!index_backup) {
        git_repo_close(&repo);
        TEST_SKIP("Could not backup index");
    }

    // Backup and modify file
    size_t orig_size = 0;
    char* orig_content = read_test_file(TEST_REPO_PATH, "file1.txt", &orig_size);

    // Modify file and stage it
    write_test_file(TEST_REPO_PATH, "file1.txt", "staged modification\n");
    git_stage_file(&repo, "file1.txt");

    // Restore file content (so worktree matches index, but index differs from HEAD)
    // Actually we need to keep the modified content staged

    GitStatus status = {};
    git_status_compute(&repo, &status);

    bool found_staged = false;
    for (size_t i = 0; i < status.staged_count; i++) {
        if (strcmp(status.staged[i].path, "file1.txt") == 0 &&
            status.staged[i].index_status == GitFileStatus::Modified) {
            found_staged = true;
            break;
        }
    }

    // Restore original file and index
    write_test_file(TEST_REPO_PATH, "file1.txt", orig_content);
    write_test_file_binary(TEST_REPO_PATH, ".git/index", index_backup, index_size);
    delete[] orig_content;
    delete[] index_backup;

    git_status_free(&status);
    git_repo_close(&repo);

    TEST_ASSERT_TRUE(found_staged);
}

