TEST(status_detect_staged_deletion) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // Backup index and file
    size_t index_size = 0;
    char* index_backup = read_test_file(TEST_REPO_PATH, ".git/index", &index_size);
    size_t file_size = 0;
    char* file_backup = read_test_file(TEST_REPO_PATH, "file2.txt", &file_size);

    if (!index_backup || !file_backup) {
        delete[] index_backup;
        delete[] file_backup;
        git_repo_close(&repo);
        TEST_SKIP("Could not backup files");
    }

    // To stage a deletion, we need to:
    // 1. Remove the file from the worktree
    // 2. Remove it from the index (using git_index_remove_path)
    delete_test_file(TEST_REPO_PATH, "file2.txt");

    // Directly manipulate index to remove file2.txt
    if (!git_index_lock(&repo, 3000)) {
        write_test_file(TEST_REPO_PATH, "file2.txt", file_backup);
        write_test_file_binary(TEST_REPO_PATH, ".git/index", index_backup, index_size);
        delete[] index_backup;
        delete[] file_backup;
        git_repo_close(&repo);
        TEST_SKIP("Could not lock index");
    }

    GitIndexFull index = {};
    bool index_opened = git_index_open_full(&repo, &index);
    if (index_opened) {
        git_index_remove_path(&index, "file2.txt");
        git_index_write(&repo, &index);
        git_index_close_full(&index);
    }
    git_index_unlock(&repo);

    GitStatus status = {};
    git_status_compute(&repo, &status);

    bool found_deleted = false;
    for (size_t i = 0; i < status.staged_count; i++) {
        if (strcmp(status.staged[i].path, "file2.txt") == 0 &&
            status.staged[i].index_status == GitFileStatus::Deleted) {
            found_deleted = true;
            break;
        }
    }

    // Restore
    write_test_file(TEST_REPO_PATH, "file2.txt", file_backup);
    write_test_file_binary(TEST_REPO_PATH, ".git/index", index_backup, index_size);
    delete[] index_backup;
    delete[] file_backup;

    git_status_free(&status);
    git_repo_close(&repo);

    TEST_ASSERT_TRUE(found_deleted);
}

