TEST(diff_unstaged_modified_file) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // Backup and modify
    size_t orig_size = 0;
    char* orig_content = read_test_file(TEST_REPO_PATH, "file1.txt", &orig_size);
    if (!orig_content) {
        git_repo_close(&repo);
        TEST_SKIP("Could not read file1.txt");
    }

    write_test_file(TEST_REPO_PATH, "file1.txt", "line1\nmodified line\nline3\n");

    FileDiff diff = {};
    bool result = diff_compute_unstaged(&repo, "file1.txt", &diff);

    // Restore before assertions
    write_test_file(TEST_REPO_PATH, "file1.txt", orig_content);
    delete[] orig_content;

    TEST_ASSERT_TRUE(result);
    TEST_ASSERT_STREQ(diff.path, "file1.txt");
    TEST_ASSERT_FALSE(diff.is_binary);
    TEST_ASSERT_FALSE(diff.is_new_file);
    TEST_ASSERT_FALSE(diff.is_deleted);

    diff_free(&diff);
    git_repo_close(&repo);
}

