// Diff Integration Tests - Staged
// ============================================================================

TEST(diff_staged_modified_file) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // Backup
    size_t index_size = 0;
    char* index_backup = read_test_file(TEST_REPO_PATH, ".git/index", &index_size);
    size_t orig_size = 0;
    char* orig_content = read_test_file(TEST_REPO_PATH, "file1.txt", &orig_size);

    if (!index_backup || !orig_content) {
        delete[] index_backup;
        delete[] orig_content;
        git_repo_close(&repo);
        TEST_SKIP("Could not backup files");
    }

    // Modify and stage
    write_test_file(TEST_REPO_PATH, "file1.txt", "staged modification for diff\n");
    git_stage_file(&repo, "file1.txt");

    FileDiff diff = {};
    bool result = diff_compute_staged(&repo, "file1.txt", &diff);

    // Restore
    write_test_file(TEST_REPO_PATH, "file1.txt", orig_content);
    write_test_file_binary(TEST_REPO_PATH, ".git/index", index_backup, index_size);
    delete[] orig_content;
    delete[] index_backup;

    TEST_ASSERT_TRUE(result);
    TEST_ASSERT_FALSE(diff.is_binary);
    TEST_ASSERT_TRUE(diff.additions > 0 || diff.deletions > 0);

    diff_free(&diff);
    git_repo_close(&repo);
}

TEST(diff_staged_new_file) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    size_t index_size = 0;
    char* index_backup = read_test_file(TEST_REPO_PATH, ".git/index", &index_size);
    if (!index_backup) {
        git_repo_close(&repo);
        TEST_SKIP("Could not backup index");
    }

    // Create and stage new file
    write_test_file(TEST_REPO_PATH, "staged_new_file.txt", "brand new staged content\n");
    git_stage_file(&repo, "staged_new_file.txt");

    FileDiff diff = {};
    bool result = diff_compute_staged(&repo, "staged_new_file.txt", &diff);

    // Restore
    delete_test_file(TEST_REPO_PATH, "staged_new_file.txt");
    write_test_file_binary(TEST_REPO_PATH, ".git/index", index_backup, index_size);
    delete[] index_backup;

    TEST_ASSERT_TRUE(result);
    TEST_ASSERT_TRUE(diff.is_new_file);
    TEST_ASSERT_TRUE(diff.additions > 0);
    TEST_ASSERT_EQ(diff.deletions, 0);

    diff_free(&diff);
    git_repo_close(&repo);
}

