TEST(diff_binary_file_detection) {
    GitRepository repo = {};
    if (!git_repo_open(&repo, TEST_REPO_PATH)) {
        TEST_SKIP("Fixture repo not found");
    }

    // Create a binary file (with null bytes)
    char binary_content[] = "start\x00middle\x00end";

    wchar_t full_path[512];
    wcscpy_s(full_path, TEST_REPO_PATH);
    wcscat_s(full_path, L"\\binary_test.bin");

    HANDLE hFile = CreateFileW(full_path, GENERIC_WRITE, 0, nullptr,
                               CREATE_ALWAYS, FILE_ATTRIBUTE_NORMAL, nullptr);
    if (hFile != INVALID_HANDLE_VALUE) {
        DWORD written;
        WriteFile(hFile, binary_content, sizeof(binary_content), &written, nullptr);
        CloseHandle(hFile);
    }

    FileDiff diff = {};
    bool result = diff_compute_unstaged(&repo, "binary_test.bin", &diff);

    DeleteFileW(full_path);

    if (result) {
        TEST_ASSERT_TRUE(diff.is_binary);
        diff_free(&diff);
    }

    git_repo_close(&repo);
}
